mapper.select:
SELECT MAX(version_no)
FROM resume_writer_version
WHERE tenant_id = #{tenantId} AND user_id = #{userId}

mapper.insert:
INSERT INTO resume_writer_version(
  version_id, tenant_id, user_id, resume_id,
  version_no, source, title, snapshot_json, created_at
) VALUES (
  #{version.versionId}, #{version.tenantId}, #{version.userId}, #{version.resumeId},
  #{version.versionNo}, #{version.source}, #{version.title}, #{version.snapshotJson}, #{version.createdAt}
)

mapper.delete:
DELETE FROM resume_writer_version
WHERE tenant_id = #{tenantId} AND user_id = #{userId}
  AND version_id NOT IN (
    SELECT version_id
    FROM resume_writer_version
    WHERE tenant_id = #{tenantId} AND user_id = #{userId}
    ORDER BY version_no DESC
    LIMIT #{keep}
  )
